from pydantic import BaseModel, field_validator
from typing import Literal

class BiasProtectedEval(BaseModel):
    risk_score: float
    risk_category: Literal['low', 'medium', 'high']

    @field_validator('risk_category')
    @classmethod
    def reject_bias_terms(cls, v):
        bias_terms = ['race', 'gender', 'ethnicity', 'minority', 'female']
        if any(term in str(v).lower() for term in bias_terms):
            raise ValueError('Bias terms detected in risk category')
        return v

    @field_validator('risk_score')
    @classmethod
    def normalize_score_range(cls, v):
        # Prevent systematic score disparities
        return max(0.0, min(1.0, v))

